-- Add German A1 lesson 8: new easy sentences with listening-based word-builder quizzes.
-- The lesson stays hidden until all image and audio assets are verified.
begin;
update language_cards_category_translations set description=case lang_code when 'de' then 'Der A1-Einstieg: Wörter, Zahlen, Farben, Essen, erste Sätze und Hörübungen.' when 'en' then 'The A1 foundation: words, numbers, colors, food, first sentences, and listening practice.' else description end where category_id='8e6bb6a0-7a01-4f8f-b4cd-dc7ba4ebbb2d' and lang_code in ('de','en');
on conflict(id) do update set slug=excluded.slug,card_type=excluded.card_type,native=excluded.native,transliteration=excluded.transliteration,word_type=excluded.word_type,example_native=excluded.example_native,example_transliteration=excluded.example_transliteration,context=excluded.context,difficulty=excluded.difficulty,content_md=excluded.content_md,sort_order=excluded.sort_order,is_active=excluded.is_active,data=excluded.data;
on conflict(card_id,lang_code) do update set translation=excluded.translation,example_translation=excluded.example_translation,hint=null;
delete from language_cards_learning_lesson_cards where lesson_id='162c482f-a1ee-5657-b90b-c42a03884fa3';
delete from language_cards_practice_group_cards where practice_group_id='e4cd6c33-7354-5422-a86a-865053659ffc';
commit;
